import type { SearchInputConfig } from '@linm-soft/common-components';
import { ktService } from '../../services/kt/ktService';
import type { MaterialDto } from '../../services/kt/models';

/** SearchInput config for danh mục vật tư — value key is material **code** */
export function createMaterialSearchConfig(): SearchInputConfig<MaterialDto> {
  return {
    api: {
      getItemKey: (m) => m.code,
      search: ({ search, page, pageSize }) =>
        ktService.searchMaterials({ search, page, pageSize }),
    },
    display: {
      getPrimaryDisplay: (m) => m.code,
      getSecondaryDisplay: (m) => m.name,
      getSingleDisplay: (m) => `${m.code} — ${m.name}`,
    },
    columns: [
      { key: 'code', variant: 'badge', render: (m) => m.code },
      { key: 'name', variant: 'primary', render: (m) => m.name },
      {
        key: 'unit',
        variant: 'meta',
        icon: 'fas fa-ruler',
        visible: (m) => !!m.unitCode,
        render: (m) => m.unitCode ?? '',
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã VT' },
        { key: 'name', label: 'Tên vật tư' },
        { key: 'unit', label: 'ĐVT' },
      ],
    },
    texts: {
      secondaryPlaceholder: 'Tên vật tư',
      empty: 'Không tìm thấy vật tư',
    },
    dropdownPortal: true,
  };
}
